+fn read_events_resource(
+    ctx: &McpContext,
+    db_path: &Arc<PathBuf>,
+    uri: &str,
+    limit: usize,
+    unhandled: bool,
+) -> McpResult<Vec<ResourceContent>> {
+    let tool = WaEventsTool::new(Arc::clone(db_path));
+    let contents = tool.call(
+        ctx,
+        serde_json::json!({
+            "limit": limit.clamp(1, 1000),
+            "unhandled": unhandled,
+        }),
+    )?;
+    tool_output_as_resource(uri, contents)
